SELECT "Modality", COUNT(*) AS "count" FROM (SELECT "SOPInstanceUID", "Modality" FROM "IDC"."IDC_V17"."DICOM_ALL" WHERE "SeriesInstanceUID" = '1.3.6.1.4.1.14519.5.2.1.3671.4754.105976129314091491952445656147' UNION SELECT s."SOPInstanceUID", d."Modality" FROM "IDC"."IDC_V17"."SEGMENTATIONS" s JOIN "IDC"."IDC_V17"."DICOM_ALL" d ON s."SOPInstanceUID" = d."SOPInstanceUID" WHERE s."segmented_SeriesInstanceUID" = '1.3.6.1.4.1.14519.5.2.1.3671.4754.105976129314091491952445656147') AS combined GROUP BY "Modality" ORDER BY "count" DESC LIMIT 1